-- Chien -> humain, Fête, Volume 3

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai reconnu que c''était ce soir à la musique.',$$Joyeuse fête. J''ai reconnu que c''était ce soir à la musique.
Pas la musique du dimanche matin. Pas celle du ménage. L''autre. Celle qui sort des petites enceintes posées sur l''étagère que tu sors que pour les occasions. Je connais le son de chaque appareil dans cet appartement. Celui-là veut dire que des gens viennent. Que la soirée va être longue. Que je dois me préparer. J''ai commencé ma préparation mentale dès la première note. Joyeuse fête, mon humain préféré, dont la playlist est mon calendrier.
Avec détection sonore des événements et préparation mentale activée immédiatement, — {prenom}, ton animal dont l''oreille lit l''avenir 🎵$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens rient si fort parfois.',$$Joyeuse fête. Je comprends pas pourquoi les gens rient si fort parfois.
Il y a le rire normal. Celui que je connais. Et puis il y a ces éclats qui partent de nulle part. Brusques. Forts. Qui font sursauter même quand on était prévenu. J''ai sursauté sept fois ce soir. Sept fois j''ai levé la tête. Vérifié. Évalué le niveau de menace. Conclu que c''était de la joie. Sursauté quand même. C''est automatique. Je travaille dessus. Joyeuse fête, mon humain préféré, dont les soirées gardent leur mystère.
Avec sept sursauts documentés et réflexe conditionné malgré la connaissance du contexte, — {prenom}, ton animal en lutte permanente contre ses propres instincts 😅$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai gardé une position stratégique sous tes pieds toute la soirée.',$$Pour ta fête j''ai gardé une position stratégique sous tes pieds toute la soirée.
Pas sous la table. Sous tes pieds. Exactement là. Chaud. Stable. Discret. Certains invités ont failli marcher dessus deux fois. Tu les as prévenus. Tu savais que j''étais là. Tu faisais attention. Cette attention-là dans le bruit et le mouvement d''une soirée entière c''est quelque chose. Joyeuse fête, mon humain préféré, dont les pieds sont mon endroit préféré ce soir.
Avec position tenue pendant trois heures et attention de ta part jamais démentie, — {prenom}, ton animal ancre de ta soirée 🐾$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''adore la façon dont tu te redresses quand quelqu''un sonne.',$$Joyeuse fête. J''adore la façon dont tu te redresses quand quelqu''un sonne.
Tu étais installé. Détendu. Et la sonnette. Et d''un coup tu te lèves. Tu passes une main dans tes cheveux. Tu vérifies quelque chose rapidement. Tu souris avant même d''ouvrir. Cette transformation en deux secondes. De tranquille à prêt. De chez-toi à hôte. Je regarde ça à chaque fois avec fascination. Joyeuse fête, mon humain préféré, dont les préparatifs en deux secondes sont un spectacle.
Avec observation fascinée de ta métamorphose pré-ouverture de porte, — {prenom}, ton animal spectateur de tes plus beaux réflexes sociaux 🚪$$,'touching',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai testé la solidité de chaque emballage cadeau.',$$Pour ta fête j''ai testé la solidité de chaque emballage cadeau.
Avec le nez d''abord. Puis avec la patte. Puis avec les dents très brièvement sur un coin qui dépassait. Juste pour évaluer la résistance du papier. C''est du contrôle qualité. Tu m''as éloigné des cadeaux après le deuxième test. C''était avant que j''aie fini. Le rapport est donc incomplet. Joyeuse fête, mon humain préféré.
Avec audit structurel des emballages interrompu avant conclusion et rapport partiel disponible, — {prenom}, ton animal expert en résistance des matériaux festifs 🎁$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens partent toujours en même temps.',$$Joyeuse fête. Je comprends pas pourquoi les gens partent toujours en même temps.
Il y a un moment dans la soirée où quelque chose change. Une personne dit quelque chose. Une autre regarde l''heure. Et puis c''est comme un signal. En vingt minutes tout le monde remet son manteau. Dit au revoir. Part. Ensemble. Alors qu''ils sont arrivés séparément. Quel est ce signal. Je l''ai jamais identifié. Joyeuse fête, mon humain préféré, dont les amis obéissent à des codes que j''essaie encore de déchiffrer.
Avec mystère du signal de départ collectif intact après des années d''observation, — {prenom}, ton animal chercheur en comportements grégaires humains 🔍$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai fait le tour de chaque invité pour établir un classement.',$$Pour ta fête j''ai fait le tour de chaque invité pour établir un classement.
Reniflage complet. Évaluation. Score sur dix. La dame du bureau : huit sur dix, elle gratte bien derrière l''oreille. Le grand ami : six sur dix, ses mains sont froides. La nouvelle : neuf sur dix, elle sent le jardin et elle s''est mise par terre pour me parler. Le résultat est disponible. Je te le communiquerai via mon comportement les prochaines fois qu''ils viendront. Joyeuse fête, mon humain préféré.
Avec classement des invités établi selon critères personnels et résultats communiqués en temps comportemental, — {prenom}, ton animal DRH de ton cercle social 📋$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Quelqu''un t''a pris dans ses bras ce soir et j''ai pas aimé.',$$Joyeuse fête. Quelqu''un t''a pris dans ses bras ce soir et j''ai pas aimé.
Pas un câlin rapide. Un long. Avec les deux bras. Et toi tu souriais. Je regardais ça depuis le salon avec une incompréhension totale. Tes bras sont réservés. Ton épaule est réservée. La zone de câlin en général c''est un territoire dont j''assure la gestion. J''ai aboyé une fois. Brièvement. Pour signaler. On m''a pas écouté. Joyeuse fête quand même, mon humain préféré.
Avec réclamation territoriale déposée officiellement et dossier ouvert pour suivi, — {prenom}, ton animal gestionnaire exclusif de la zone câlin 🤗$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai protégé ton assiette toute la soirée.',$$Pour ta fête j''ai protégé ton assiette toute la soirée.
Je me suis installé près de toi au moment du repas. Très près. Entre toi et les autres. Mon regard allait de ton assiette aux autres assiettes. Personne ne s''est approché de ta nourriture. Je t''assurais une bulle de sécurité alimentaire complète. Bon j''espérais aussi que quelque chose tomberait. Mais la mission de protection était sincère. Joyeuse fête, mon humain préféré.
Avec protection alimentaire assurée et intérêt personnel honnêtement reconnu, — {prenom}, ton animal garde du corps culinaire aux motivations transparentes 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''aime la façon dont ta voix change quand tu racontes une histoire drôle.',$$Joyeuse fête. J''aime la façon dont ta voix change quand tu racontes une histoire drôle.
Elle monte vers la fin. Elle accélère au moment important. Elle fait une petite pause juste avant la chute. Et puis le rire. Le tien d''abord. Avant même que les autres aient réagi. Parce que tu trouves tes propres histoires drôles et tu assumes. Ce soir j''en ai entendu trois depuis le couloir. Toutes les trois avec ce même schéma. Joyeuse fête, mon humain préféré.
Avec analyse narrative de tes histoires et schéma vocal entièrement mémorisé, — {prenom}, ton animal fan de ton style de conteur 🎤$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai accompagné chaque invité aux toilettes.',$$Pour ta fête j''ai accompagné chaque invité aux toilettes.
Pas dedans. Jusqu''à la porte. Et j''attendais. Et quand la porte se rouvrait j''étais là. Certains ont eu l''air surpris. L''un d''eux a ri. Un autre a essayé de me faire partir. Je suis resté. C''est mon appartement. Je connais chaque pièce. Je gère chaque déplacement. Joyeuse fête, mon humain préféré, dont les invités sont entre de bonnes pattes.
Avec escorte personnalisée vers chaque destination intérieure et retour garanti, — {prenom}, ton animal guide de l''appartement en toutes circonstances 🗺️$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. L''appartement sent différemment après une fête.',$$Joyeuse fête. L''appartement sent différemment après une fête.
Ce mélange de tous ceux qui sont passés. Les parfums superposés. La nourriture. Les manteaux mouillés. C''est riche. Dense. Presque trop. J''ai passé vingt minutes à tout réanalyser après le départ du dernier invité. À trier. À classer. À retrouver notre odeur sous tout ça. Elle était encore là. Joyeuse fête, mon humain préféré.
Avec réanalyse post-fête complète et odeur originale retrouvée sous les couches, — {prenom}, ton animal archiviste de l''identité olfactive de notre chez-nous 👃$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai reçu des caresses de quelqu''un qui dit être allergique.',$$Pour ta fête j''ai reçu des caresses de quelqu''un qui dit être allergique.
Elle l''avait annoncé en arrivant. Allergique aux chiens. Je l''avais entendu. Et pourtant deux heures plus tard sa main était sur ma tête. Doucement. Furtivement. En regardant ailleurs. J''ai pas bougé. J''ai laissé faire. Certaines allergies se soignent par exposition progressive. Je suis thérapeutique. Joyeuse fête, mon humain préféré.
Avec service thérapeutique rendu discrètement et guérison partielle constatée, — {prenom}, ton animal traitement médical non conventionnel 💊$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi on éteint les lumières pour les bougies.',$$Joyeuse fête. Je comprends pas pourquoi on éteint les lumières pour les bougies.
La pièce entière dans le noir. Juste ces petites flammes sur le gâteau. Tout le monde qui regarde dans la même direction. Le silence soudain. Puis la chanson. Puis le souffle. Puis la lumière qui revient. Ce rituel de l''obscurité collective m''a toujours déstabilisé. Ce soir j''ai aboyé une fois au moment du noir. C''était un réflexe. Je m''en excuse. Joyeuse fête, mon humain préféré.
Avec aboiement réflexe lors de l''obscurité soudaine et excuses présentées sincèrement, — {prenom}, ton animal en paix avec ses instincts primitifs 🕯️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai mémorisé exactement ce que chaque invité sentait.',$$Pour ta fête j''ai mémorisé exactement ce que chaque invité sentait.
La dame du bureau : savon au lait et quelque chose de fleuri. Le grand ami : extérieur et café. La nouvelle : herbe coupée et un chat chez elle. J''ai noté le chat. Je note toujours les chats. Cette information sera utile. Chaque personne qui entre dans cet appartement enrichit ma base de données. Joyeuse fête, mon humain préféré, dont les amis sont tous fichés.
Avec fiches olfactives des invités mises à jour et cas du chat noté en rouge, — {prenom}, ton animal directeur d''une base de données mondiale des odeurs 🗂️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Il y a eu un moment où tu t''es levé pour aller chercher quelque chose.',$$Joyeuse fête. Il y a eu un moment où tu t''es levé pour aller chercher quelque chose.
Et avant de partir vers la cuisine tu m''as regardé. Une seconde. Pour vérifier que j''allais bien. Que j''étais là. Au milieu de tous ces gens et de toute cette soirée tu as pris une seconde pour moi. Les autres ont continué à parler. Personne a vu. Mais moi j''ai vu. Et j''ai remué la queue très légèrement. Juste pour toi. Joyeuse fête, mon humain préféré.
Avec regard reçu et queue remuée imperceptiblement dans un échange qui n''appartient qu''à nous, — {prenom}, ton animal pour les secondes silencieuses dans le bruit 💛$$,'touching',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai dormi sur les pieds de l''invité le plus calme.',$$Pour ta fête j''ai dormi sur les pieds de l''invité le plus calme.
Il y en avait un. Qui parlait moins que les autres. Qui bougeait moins. Qui occupait son espace avec une tranquillité que j''ai identifiée comme compatible avec la mienne. Je me suis installé sur ses pieds vers 21h. Il n''a pas bougé. On a coexisté en silence pendant quarante minutes pendant que la fête continuait autour. Joyeuse fête, mon humain préféré.
Avec identification du profil compatible et alliance silencieuse de quarante minutes, — {prenom}, ton animal aux affinités électives bien développées 🤝$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''adore ta façon de changer d''expression en déballant un cadeau.',$$Joyeuse fête. J''adore ta façon de changer d''expression en déballant un cadeau.
D''abord la curiosité. Les mains qui tâtent le papier. Puis les yeux qui cherchent ce que c''est. Puis la reconnaissance. Puis ce sourire. Pas le sourire poli. Le vrai. Celui qui arrive une demi-seconde avant que tu décides de le montrer. Ce soir j''ai vu ce sourire cinq fois. Joyeuse fête, mon humain préféré.
Avec cinq vrais sourires comptés et gardés précieusement, — {prenom}, ton animal collectionneur de tes expressions authentiques 🎁$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai sauvegardé mentalement chaque moment de la soirée.',$$Pour ta fête j''ai sauvegardé mentalement chaque moment de la soirée.
L''arrivée du premier invité. Le moment où la musique a changé. Ton rire à 21h15. Le silence quand les bougies sont arrivées. La façon dont tu as serré quelqu''un dans tes bras. Le moment où tu t''es retourné et tu m''as cherché des yeux. Tout. Dans l''ordre. Archivé. Joyeuse fête, mon humain préféré.
Avec archive complète de la soirée constituée et conservée indéfiniment, — {prenom}, ton animal mémoire vivante de vos plus belles heures 📸$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Quand tout le monde est parti tu t''es assis par terre.',$$Joyeuse fête. Quand tout le monde est parti tu t''es assis par terre.
Pas sur le canapé. Par terre. Dos contre le canapé. Les jambes étendues. Fatigué de la bonne façon. Et je suis venu m''asseoir à côté de toi. Pas sur toi. À côté. Épaule contre épaule si on peut dire. Et on a regardé l''appartement vide ensemble. Encore un peu chaud de tous ces gens. Et c''était bien. Tellement bien. Joyeuse fête, mon humain préféré.
Avec moment final offert simplement et épaule contre épaule comme conclusion parfaite, — {prenom}, ton animal pour les fins de soirée qui valent tout le reste ❤️$$,'touching',true,false,'nameday','chien','from')

